#include <bits/stdc++.h>
using namespace std;

const int N=2e3+10;

struct Node{
    bitset<N/2> a;
    int id;
}w[N];

int n,m;
char s[N];

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,x;i<=m;i++){
        scanf("%s%d",s,&x);
        for(int j=0;j<n;j++)
            w[i].a[j]=s[j]-'0';
        w[i].a[n]=x;
        w[i].id=i;
    }
    if(m<n){
        printf("Cannot Determine");
        return 0;
    }
    w[m+1].id=m+1;
    for(int i=1;i<=n;i++){
        int r=m+1;
        for(int j=i;j<=m;j++)
            if(w[j].a[i-1] && w[j].id<w[r].id)
                r=j;
        if(r>m){
            printf("Cannot Determine");
            return 0;
        }
        swap(w[i],w[r]);
        for(int j=i+1;j<=m;j++)
            if(w[j].a[i-1])
                w[j].a^=w[i].a;
    }
    int ans=0;
    for(int i=n;i;i--){
        ans=max(ans,w[i].id);
        for(int j=1;j<i;j++)
            if(w[j].a[i-1])
                w[j].a^=w[i].a;
    }
    printf("%d\n",ans);
    for(int i=1;i<=n;i++)
        if(w[i].a[n])
            puts("?y7M#");
        else
            puts("Earth");
    return 0;
}
